--
-- Extraindo dados da tabela `historia`
--

INSERT INTO `historia` (`id`, `titulo`, `subtitulo`, `conteudo`, `imagem`) VALUES
(6, '2020', 'REVOLUÇÃO FRANCESA', 'A Revolução Francesa foi um ciclo revolucionário de grandes proporções que se espalhou pela França e aconteceu entre 1789 e 1799. Foi inspirada nos ideais do Iluminismo e motivada pela situação de crise que a França vivia no final do século XVIII.', );
INSERT INTO `historia` (`id`, `titulo`, `subtitulo`, `conteudo`, `imagem`) VALUES
(7, '2022', 'REPUBLICA VELHA', 'A República Velha, também conhecida como Primeira República, é a primeira fase da república brasileira e estendeu-se de 1889 a 1930. Esse período ficou profundamente marcado na história brasileira por ter sido quando as grandes oligarquias controlavam a política do Brasil por meio de esquemas de troca de favores.', ),
(8, '2018', 'BRASIL COLÔNIAL', 'O Brasil Colônia, ou Brasil colonial, existiu entre o século XVI e o início do XIX, quando o atual território brasileiro abrigava colônias do Reino de Portugal, fazendo parte de um conceito mais amplo: a América Portuguesa.', );
INSERT INTO `historia` (`id`, `titulo`, `subtitulo`, `conteudo`, `imagem`) VALUES
(9, '2017', 'PRIMEIRA GUERRA MUNDIAL', 'A Primeira Guerra Mundial foi um conflito bélico global centrado na Europa, que começou em 28 de julho de 1914 e durou até 11 de novembro de 1918. A guerra envolveu as grandes potências de todo o mundo, que se organizaram em duas alianças opostas: os Aliados e os Impérios Centrais.', );
INSERT INTO `historia` (`id`, `titulo`, `subtitulo`, `conteudo`, `imagem`) VALUES
(10, '2015', 'INDEPENDENCIA DAS TREZE COLÔNIAS', '\"\r\nA Independência dos Estados Unidos foi declarada no dia 4 de julho de 1776 e colocou fim ao vínculo colonial que existia entre as Treze Colônias (nome pelo qual a região era conhecida nesse período) e a Inglaterra. Com essa conquista, os Estados Unidos transformaram-se na primeira nação do continente americano a ter sua independência.\"', );
INSERT INTO `historia` (`id`, `titulo`, `subtitulo`, `conteudo`, `imagem`) VALUES
(11, '2014', '', 'Política do café com leite derivou-se da \"Política dos Governadores\" e visava a predominância do poder nacional por parte das oligarquias paulista e mineira, executada na República Velha a partir da Presidência de Campos Sales (1898-1902), por presidentes civis fortemente influenciados pelo setor agrário dos estados de São Paulo — com grande produção de café — e Minas Gerais — produtor de leite e maior polo eleitoral do país de então —, impedindo que o principal cargo do Poder Executivo fosse ocupado por representante dos interesses de outros estados economicamente importantes à época, como Rio Grande do Sul e Pernambuco. Essa política perdurou até a Revolução de 1930.', );
INSERT INTO `historia` (`id`, `titulo`, `subtitulo`, `conteudo`, `imagem`) VALUES
(12, '2011', 'BRASIL IMPERIAL', 'O Brasil Império compreende o período de 1822 a 1889 quando o país foi governado por uma monarquia constitucional. Esta época teve início com a aclamação do Imperador D. Pedro I, em 1822, e se prolongou até a Proclamação da República, em 1889.', );
INSERT INTO `historia` (`id`, `titulo`, `subtitulo`, `conteudo`, `imagem`) VALUES
(13, '2009', 'ESCRAVIDÃO NO BRASIL', 'A escravidão no Brasil teve início no século XVI, durante o Período Colonial, e consistiu no uso da mão-de-obra forçada de mulheres e homens africanos. Essas pessoas foram retiradas a força dos muitos grupos étnicos dos quais faziam parte no continente africano e trazidas ao Brasil nos chamados navios negreiros.', );

