INSERT INTO `pg_index1` (`id`, `titulo`, `subtitulo`, `conteudo`, `imagem`) VALUES
(8, '', '', 'Bem-vindo ao nosso site! Aqui, você encontrará informações valiosas sobre o Exame Nacional do Ensino Médio (Enem). Nosso objetivo é ajudá-lo a se preparar para o exame, fornecendo acesso a todos os conteúdos que já caíram nas provas anteriores.\r\n\r\nSabemos que o Enem é um dos exames mais importantes do país, e muitos estudantes se sentem perdidos ao se preparar para ele. É por isso que decidimos criar um site que disponibiliza todos os conteúdos que já foram aplicados nas provas do Enem.', ),
(9, '', '', 'Ao acessar o nosso site, você poderá encontrar conteúdos de todas as áreas do conhecimento, incluindo Matemática, Português, História, Geografia, Biologia, Física e Química. Além disso, você poderá fazer simulados com conteúdos das provas anteriores, para se preparar ainda mais para o exame.', );
INSERT INTO `pg_index1` (`id`, `titulo`, `subtitulo`, `conteudo`, `imagem`) VALUES
(10, '', '', 'Acreditamos que o conhecimento é a chave para o sucesso, e queremos ajudar todos os estudantes que estão se preparando para o Enem. Por isso, nosso site é gratuito e acessível a todos. Não importa se você é um estudante que está se preparando para o exame pela primeira vez, ou se já fez o Enem antes e quer se preparar melhor - estamos aqui para ajudar.\r\n\r\nEntão, não perca mais tempo! Acesse nosso site e comece a se preparar para o Enem hoje mesmo. Com todos os conteúdos que disponibilizamos, você terá muito mais chances de fazer uma excelente prova e conquistar o seu sonho de entrar na universidade.', );

